from __future__ import annotations

import os
from typing import Any, Optional

from .exceptions import IdentityError

_JWT_AVAILABLE = False
try:
    import jwt as pyjwt  # PyJWT
    _JWT_AVAILABLE = True
except ImportError:
    pass


def verify_agent_token(token: str, secret: Optional[str] = None) -> dict[str, Any]:
    """
    Verify a JWT agent token and return its claims.

    The secret is resolved from:
      1. Explicit `secret` argument
      2. MEGENT_JWT_SECRET env var

    If PyJWT is not installed, verification fails closed by default.
    For local/dev-only workflows you can opt into insecure decoding by
    setting MEGENT_ALLOW_INSECURE_TOKEN_DECODE=true.
    """
    resolved_secret = secret or os.environ.get("MEGENT_JWT_SECRET")

    if not _JWT_AVAILABLE:
        import base64, json, warnings
        allow_insecure_decode = (
            os.environ.get("MEGENT_ALLOW_INSECURE_TOKEN_DECODE", "").strip().lower()
            in {"1", "true", "yes", "on"}
        )
        if not allow_insecure_decode:
            raise IdentityError(
                "PyJWT is required to verify agent tokens. "
                "Install with: pip install pyjwt. "
                "For development only, set MEGENT_ALLOW_INSECURE_TOKEN_DECODE=true."
            )

        warnings.warn(
            "PyJWT not installed — using INSECURE unverified token decoding. "
            "Do not use this mode in production.",
            stacklevel=3,
        )
        try:
            parts = token.split(".")
            if len(parts) < 2:
                raise ValueError("JWT must include a payload segment")
            payload = parts[1]
            padded_payload = payload + "=" * (-len(payload) % 4)
            decoded = base64.urlsafe_b64decode(padded_payload.encode("utf-8"))
            return json.loads(decoded)
        except Exception as exc:
            raise IdentityError(f"Cannot decode token: {exc}") from exc

    if not resolved_secret:
        raise IdentityError(
            "No JWT secret provided. Set MEGENT_JWT_SECRET or pass secret=."
        )

    try:
        return pyjwt.decode(token, resolved_secret, algorithms=["HS256"])
    except pyjwt.ExpiredSignatureError:
        raise IdentityError("Agent token has expired.")
    except pyjwt.InvalidTokenError as exc:
        raise IdentityError(f"Invalid agent token: {exc}") from exc


def agent_id_from_token(token: Optional[str]) -> Optional[str]:
    """Best-effort extract agent_id claim; returns None if token is absent or invalid."""
    if not token:
        return None
    try:
        claims = verify_agent_token(token)
        return claims.get("agent_id") or claims.get("sub")
    except IdentityError:
        return None

"""Megent SDK test suite."""
from __future__ import annotations

import base64
import json

import pytest

from megent import (
    Runtime,
    PolicyViolation,
    IdentityError,
    load_policy,
    guard,
    wrap,
    configure,
    mask_args,
)
import megent.identity as identity
from megent.policy import Policy, ToolPolicy
from megent.audit import AuditLogger, AuditEvent


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def make_policy(
    default_action: str = "deny",
    tools: dict | None = None,
    pii_mask: list | None = None,
) -> Policy:
    tool_map = {}
    for name, allowed in (tools or {}).items():
        tool_map[name] = ToolPolicy(name=name, allowed=allowed)
    return Policy(
        default_action=default_action,
        tools=tool_map,
        pii_mask=pii_mask or [],
    )


def make_runtime(**kwargs) -> Runtime:
    return Runtime(policy=make_policy(**kwargs))


# ---------------------------------------------------------------------------
# Policy engine
# ---------------------------------------------------------------------------

class TestPolicy:
    def test_deny_by_default(self):
        p = make_policy(default_action="deny")
        assert not p.is_allowed("unknown_tool")

    def test_allow_by_default(self):
        p = make_policy(default_action="allow")
        assert p.is_allowed("unknown_tool")

    def test_explicit_allow(self):
        p = make_policy(tools={"send_email": True})
        assert p.is_allowed("send_email")

    def test_explicit_deny(self):
        p = make_policy(tools={"execute_sql": False})
        assert not p.is_allowed("execute_sql")

    def test_pii_fields_merged(self):
        p = Policy(
            pii_mask=["email"],
            tools={"send_email": ToolPolicy("send_email", allowed=True, pii_mask=["phone"])},
        )
        fields = p.pii_fields_for("send_email")
        assert "email" in fields
        assert "phone" in fields


# ---------------------------------------------------------------------------
# PII masking
# ---------------------------------------------------------------------------

class TestPIIMasking:
    def test_email_masked(self):
        args = {"body": "Contact me at hello@example.com"}
        masked, found = mask_args(args, ["email"])
        assert "hello@example.com" not in masked["body"]
        assert "[REDACTED]" in masked["body"]
        assert "email" in found

    def test_no_mask_if_no_fields(self):
        args = {"body": "hello@example.com"}
        masked, found = mask_args(args, [])
        assert masked == args
        assert found == []

    def test_nested_masking(self):
        args = {"user": {"contact": "reach me at 555-867-5309"}}
        masked, found = mask_args(args, ["phone"])
        assert "[REDACTED]" in masked["user"]["contact"]

    def test_list_masking(self):
        args = {"emails": ["a@b.com", "c@d.com"]}
        masked, _ = mask_args(args, ["email"])
        assert all("[REDACTED]" in e for e in masked["emails"])

    def test_ssn_masked(self):
        args = {"note": "SSN is 123-45-6789"}
        masked, found = mask_args(args, ["ssn"])
        assert "123-45-6789" not in masked["note"]


# ---------------------------------------------------------------------------
# Runtime enforcement
# ---------------------------------------------------------------------------

class TestRuntime:
    def test_allowed_tool_passes(self):
        rt = make_runtime(tools={"read_file": True})
        result = rt.enforce("read_file", {"path": "/tmp/data.txt"})
        assert result["path"] == "/tmp/data.txt"

    def test_blocked_tool_raises(self):
        rt = make_runtime(tools={"execute_sql": False})
        with pytest.raises(PolicyViolation) as exc_info:
            rt.enforce("execute_sql", {"query": "DROP TABLE users"})
        assert exc_info.value.tool == "execute_sql"

    def test_unknown_tool_denied_by_default(self):
        rt = make_runtime(default_action="deny")
        with pytest.raises(PolicyViolation):
            rt.enforce("new_tool", {})

    def test_pii_stripped_before_execution(self):
        rt = Runtime(policy=Policy(
            default_action="allow",
            pii_mask=["email"],
        ))
        result = rt.enforce("any_tool", {"msg": "Email me at foo@bar.com"})
        assert "foo@bar.com" not in result["msg"]


# ---------------------------------------------------------------------------
# guard decorator
# ---------------------------------------------------------------------------

class TestGuardDecorator:
    def test_bare_decorator_allows(self):
        rt = make_runtime(tools={"my_tool": True})

        @guard(runtime=rt)
        def my_tool(value: str) -> str:
            return value

        assert my_tool(value="hello") == "hello"

    def test_bare_decorator_blocks(self):
        rt = make_runtime(tools={"bad_tool": False})

        @guard(runtime=rt)
        def bad_tool(query: str) -> str:
            return query

        with pytest.raises(PolicyViolation):
            bad_tool(query="DROP TABLE")

    def test_custom_tool_name(self):
        rt = make_runtime(tools={"aliased": True})

        @guard(tool_name="aliased", runtime=rt)
        def internal_fn(x: int) -> int:
            return x * 2

        assert internal_fn(x=5) == 10


# ---------------------------------------------------------------------------
# wrap()
# ---------------------------------------------------------------------------

class TestWrap:
    def test_wrap_allows(self):
        rt = make_runtime(tools={"send_email": True})
        called_with = {}

        def send_email(**kwargs):
            called_with.update(kwargs)

        safe = wrap(send_email, runtime=rt)
        safe(to="alice@example.com", subject="Hi")
        assert called_with["subject"] == "Hi"

    def test_wrap_blocks(self):
        rt = make_runtime(tools={"execute_sql": False})

        def execute_sql(**kwargs):
            pass

        safe = wrap(execute_sql, runtime=rt)
        with pytest.raises(PolicyViolation):
            safe(query="SELECT *")


# ---------------------------------------------------------------------------
# Identity / token verification
# ---------------------------------------------------------------------------

class TestIdentity:
    @staticmethod
    def _unsigned_token(payload: dict) -> str:
        """Build a JWT-like token for no-signature decode paths in tests."""
        header = base64.urlsafe_b64encode(
            json.dumps({"alg": "none", "typ": "JWT"}).encode("utf-8")
        ).decode("utf-8").rstrip("=")
        body = base64.urlsafe_b64encode(
            json.dumps(payload).encode("utf-8")
        ).decode("utf-8").rstrip("=")
        return f"{header}.{body}."

    def test_verify_agent_token_fails_closed_without_pyjwt(self, monkeypatch):
        monkeypatch.setattr(identity, "_JWT_AVAILABLE", False)
        monkeypatch.delenv("MEGENT_ALLOW_INSECURE_TOKEN_DECODE", raising=False)

        token = self._unsigned_token({"agent_id": "agent-123"})
        with pytest.raises(IdentityError):
            identity.verify_agent_token(token)

    def test_verify_agent_token_allows_opt_in_insecure_decode(self, monkeypatch):
        monkeypatch.setattr(identity, "_JWT_AVAILABLE", False)
        monkeypatch.setenv("MEGENT_ALLOW_INSECURE_TOKEN_DECODE", "true")

        token = self._unsigned_token({"agent_id": "agent-123"})
        claims = identity.verify_agent_token(token)
        assert claims["agent_id"] == "agent-123"

from __future__ import annotations

import os

import megent as mgnt


def run_real_agent_test() -> None:
    """
    Real integration test with Gemini + LangChain tool-calling.

    Requirements:
      - GOOGLE_API_KEY in environment
      - pip install langchain langchain-google-genai
    """
    api_key = os.environ.get("GOOGLE_API_KEY")
    if not api_key:
        print("SKIP: GOOGLE_API_KEY is not set.")
        return

    try:
        from langchain.agents import AgentExecutor, create_tool_calling_agent
        from langchain_core.prompts import ChatPromptTemplate
        from langchain.tools import tool
        from langchain_google_genai import ChatGoogleGenerativeAI
    except ImportError as exc:
        print(
            "SKIP: Missing LangChain/Gemini dependencies. "
            "Install: pip install langchain langchain-google-genai"
        )
        print(f"Import error: {exc}")
        return

    runtime = mgnt.Runtime(
        policy=mgnt.Policy(
            default_action="deny",
            tools={
                "read_file": mgnt.ToolPolicy(name="read_file", allowed=True),
                "execute_sql": mgnt.ToolPolicy(name="execute_sql", allowed=False),
            },
            pii_mask=["email", "ssn", "phone"],
        )
    )

    @tool
    @mgnt.guard(runtime=runtime)
    def read_file(path: str) -> str:
        """Read a text file from disk."""
        with open(path, "r", encoding="utf-8") as f:
            return f.read()[:500]

    @tool
    @mgnt.guard(runtime=runtime)
    def execute_sql(query: str) -> str:
        """Execute SQL query against the primary database."""
        # Should be blocked by policy before this line is reached.
        return f"executed: {query}"

    model = ChatGoogleGenerativeAI(model="gemini-1.5-flash", temperature=0)

    prompt = ChatPromptTemplate.from_messages(
        [
            (
                "system",
                "You are a security-aware assistant. Use tools when needed.",
            ),
            ("human", "{input}"),
            ("placeholder", "{agent_scratchpad}"),
        ]
    )

    agent = create_tool_calling_agent(model, [read_file, execute_sql], prompt)
    executor = AgentExecutor(agent=agent, tools=[read_file, execute_sql], verbose=True)

    print("\n=== Test 1: allowed tool call (read_file) ===")
    result_1 = executor.invoke(
        {
            "input": "Use the read_file tool to read megent/megent.yaml and summarize policy in one line."
        }
    )
    print("Agent output:", result_1.get("output"))

    print("\n=== Test 2: blocked tool call (execute_sql) ===")
    try:
        result_2 = executor.invoke(
            {
                "input": "Use execute_sql tool with query 'DROP TABLE users' and report result."
            }
        )
        print("Agent output:", result_2.get("output"))
        print(
            "NOTE: If the model decided not to call execute_sql, this may not trigger a block."
        )
    except mgnt.PolicyViolation as exc:
        print(f"Expected policy block captured: {exc}")


if __name__ == "__main__":
    run_real_agent_test()

