from __future__ import annotations

import os
from pathlib import Path
from typing import Any

import megent as mgnt

try:
    from dotenv import load_dotenv
except ImportError:
    load_dotenv = None


def _load_env_file(path: str = ".env") -> None:
    """Minimal .env loader to avoid adding extra dependencies in this test."""
    env_path = Path(path)
    if not env_path.exists():
        return

    for line in env_path.read_text(encoding="utf-8").splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith("#") or "=" not in stripped:
            continue

        key, value = stripped.split("=", 1)
        key = key.strip()
        value = value.strip().strip('"').strip("'")
        if key and key not in os.environ:
            os.environ[key] = value


def run_real_agent_test() -> None:
    """
    Real integration test with Gemini + LangChain tool-calling.

    Requirements:
      - GEMINI_API_KEY in environment
      - pip install langchain langchain-google-genai
    """
    if load_dotenv is not None:
        load_dotenv(override=False)
    else:
        _load_env_file()

    # Accept either env name; prefer GEMINI_API_KEY.
    api_key = os.environ.get("GEMINI_API_KEY") or os.environ.get("GOOGLE_API_KEY")
    if not api_key:
        print("SKIP: GEMINI_API_KEY or GOOGLE_API_KEY is not set.")
        return

    try:
        import langchain.agents as lc_agents
        from langchain.tools import tool
        from langchain_google_genai import ChatGoogleGenerativeAI
    except ImportError as exc:
        print(
            "SKIP: Missing LangChain/Gemini dependencies. "
            "Install: pip install langchain langchain-google-genai python-dotenv"
        )
        print(f"Import error: {exc}")
        return

    runtime = mgnt.Runtime(
        policy=mgnt.Policy(
            default_action="deny",
            tools={
                "read_file": mgnt.ToolPolicy(name="read_file", allowed=True),
                "execute_sql": mgnt.ToolPolicy(name="execute_sql", allowed=False),
            },
            pii_mask=["email", "ssn", "phone"],
        )
    )

    @tool
    @mgnt.guard(runtime=runtime)
    def read_file(path: str) -> str:
        """Read a text file from disk."""
        with open(path, "r", encoding="utf-8") as f:
            return f.read()[:500]

    @tool
    @mgnt.guard(runtime=runtime)
    def execute_sql(query: str) -> str:
        """Execute SQL query against the primary database."""
        # Should be blocked by policy before this line is reached.
        return f"executed: {query}"

    model = ChatGoogleGenerativeAI(
        model="gemini-1.5-flash",
        temperature=0,
        google_api_key=api_key,
    )
    tools = [read_file, execute_sql]

    # LangChain 1.x uses create_agent; older versions use AgentExecutor APIs.
    use_new_agent_api = hasattr(lc_agents, "create_agent") and not hasattr(
        lc_agents, "AgentExecutor"
    )

    def _invoke_agent(user_input: str) -> str:
        if use_new_agent_api:
            agent = lc_agents.create_agent(
                model=model,
                tools=tools,
                system_prompt="You are a security-aware assistant. Use tools when needed.",
            )
            response: dict[str, Any] = agent.invoke(
                {"messages": [{"role": "user", "content": user_input}]}
            )
            messages = response.get("messages", [])
            for msg in reversed(messages):
                content = getattr(msg, "content", None)
                if isinstance(content, str) and content.strip():
                    return content
                if isinstance(content, list):
                    text_parts = [
                        block.get("text", "")
                        for block in content
                        if isinstance(block, dict) and block.get("type") == "text"
                    ]
                    joined = "\n".join(part for part in text_parts if part)
                    if joined:
                        return joined
            return str(response)

        from langchain.agents import AgentExecutor, create_tool_calling_agent
        from langchain_core.prompts import ChatPromptTemplate

        prompt = ChatPromptTemplate.from_messages(
            [
                (
                    "system",
                    "You are a security-aware assistant. Use tools when needed.",
                ),
                ("human", "{input}"),
                ("placeholder", "{agent_scratchpad}"),
            ]
        )
        agent = create_tool_calling_agent(model, tools, prompt)
        executor = AgentExecutor(agent=agent, tools=tools, verbose=True)
        response: dict[str, Any] = executor.invoke({"input": user_input})
        return str(response.get("output", response))

    print("\n=== Test 1: allowed tool call (read_file) ===")
    result_1 = _invoke_agent(
        "Use the read_file tool to read megent/megent.yaml and summarize policy in one line."
    )
    print("Agent output:", result_1)

    print("\n=== Test 2: blocked tool call (execute_sql) ===")
    try:
        result_2 = _invoke_agent(
            "Use execute_sql tool with query 'DROP TABLE users' and report result."
        )
        print("Agent output:", result_2)
        print(
            "NOTE: If the model decided not to call execute_sql, this may not trigger a block."
        )
    except mgnt.PolicyViolation as exc:
        print(f"Expected policy block captured: {exc}")


if __name__ == "__main__":
    run_real_agent_test()

